**Block Scope (let and const):**
Variables declared with let and const are limited to the block where they are defined.
Example: Inside a loop or conditional block.
```js
function blockScopeExample() {
  if (true) {
    let blockScopedVariable = "I am block scoped!";
    const anotherBlockScoped = "I am also block scoped!";
    console.log(blockScopedVariable); // Works
    console.log(anotherBlockScoped); // Works
  }
  console.log(blockScopedVariable); // Error: blockScopedVariable is not defined
  console.log(anotherBlockScoped);  // Error: anotherBlockScoped is not defined
}
blockScopeExample();
```

**Function Scope (var):**
Variables declared with var are limited to the nearest function.
If declared outside any function, they become global variables.
Example:

```js
function functionScopeExample() {
  if (true) {
    var functionScopedVariable = "I am function scoped!";
  }
  console.log(functionScopedVariable); // Works because var is function-scoped
}
functionScopeExample();
console.log(functionScopedVariable); // Error: functionScopedVariable is not defined (outside the function)

```

**Avoiding Hoisting Pitfalls:**
Always declare variables at the top of the scope.
Use let and const to prevent accidental usage before declaration.
Example:

```js
// Using var - prone to hoisting issues
function hoistingWithVar() {
  console.log(myVar); // undefined (hoisted declaration, but not the value)
  var myVar = "Hoisted with var!";
  console.log(myVar); // Hoisted with var!
}

// Using let/const - avoids pitfalls
function hoistingWithLetConst() {
  console.log(myLet); // Error: Cannot access 'myLet' before initialization
  let myLet = "No hoisting issues with let!";
  console.log(myLet); // No hoisting issues with let!
}

hoistingWithVar();
hoistingWithLetConst();
```


**Best Practices:**
Prefer const for values that don’t change.
Use let for values that need to be reassigned.
Avoid using var unless necessary for legacy code.
Example:

```js
// Prefer const for values that don't change
const PI = 3.14159;
console.log(PI); // 3.14159
// PI = 3.14; // Error: Assignment to constant variable

// Use let for variables that need reassignment
let counter = 0;
counter += 1;
console.log(counter); // 1

// Avoid var unless required for legacy reasons
var legacyVar = "I'm part of old code.";
console.log(legacyVar); // I'm part of old code.
```

